// @ts-nocheck
/** Shared index-health view: unused / duplicate / redundant indexes + usage
 *  stats. Used by the DBA Ops panel and the DPA Observability panel. Read-only
 *  advisory — generates DROP DDL for the DBA to review. */
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import {
  RefreshCw, Copy, CopyCheck, Layers, TrendingDown, Search, ArrowRight,
  CircleSlash, FileWarning, Sparkles, Activity, Database as DbIcon,
  CheckCircle2, AlertTriangle, Loader2,
} from 'lucide-react';
import { api } from '../../lib/api';
import { notify, notifyError } from '../../lib/notify';
import { AiAnalysisButton } from '../../components/ai/AiAnalysisButton';

function bytes(n: number | null | undefined): string {
  if (n == null) return '—';
  const u = ['B', 'KB', 'MB', 'GB', 'TB'];
  let i = 0, v = Number(n);
  while (v >= 1024 && i < u.length - 1) { v /= 1024; i++; }
  return `${v.toFixed(v >= 10 || i === 0 ? 0 : 1)} ${u[i]}`;
}

type Tab = 'unused' | 'duplicates' | 'usage';

export function IndexHealthView({
  connectionId,
  databases,
  db,
  setDb,
  /** When true, the view manages its own database picker state (DPA usage). */
  embedded = false,
}: {
  connectionId: string;
  databases: string[];
  db: string;
  setDb: (s: string) => void;
  embedded?: boolean;
}) {
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [tab, setTab] = useState<Tab>('unused');
  const [copied, setCopied] = useState<string | null>(null);

  const check = useCallback(async () => {
    if (!db) { setData(null); return; }
    setLoading(true);
    try {
      const r = await api.indexHealth(connectionId, db);
      setData(r);
    } catch (e) {
      notifyError(e, 'Indexes');
    } finally {
      setLoading(false);
    }
  }, [connectionId, db]);

  useEffect(() => { check(); }, [check]);

  const copy = async (key: string, sql: string) => {
    try {
      await navigator.clipboard.writeText(sql);
      setCopied(key);
      setTimeout(() => setCopied((c) => (c === key ? null : c)), 1400);
      notify('DROP SQL copied to clipboard.', 'Indexes');
    } catch {
      notifyError('Clipboard unavailable.', 'Indexes');
    }
  };

  const copyAll = async (sqls: string[]) => {
    if (!sqls.length) return;
    await copy('all', sqls.join('\n'));
  };

  const avail = data?.available !== false;
  const summary = data?.summary;
  const unusedRows: any[] = data?.unused ?? [];
  const dupRows: any[] = data?.duplicates ?? [];
  const usageRows: any[] = data?.usage ?? [];

  const SUBTABS: { id: Tab; label: string; icon: any; count: number }[] = [
    { id: 'unused', label: 'Unused', icon: CircleSlash, count: unusedRows.length },
    { id: 'duplicates', label: 'Duplicates', icon: Copy, count: dupRows.length },
    { id: 'usage', label: 'Usage stats', icon: Activity, count: usageRows.length },
  ];

  return (
    <div className={embedded ? 'space-y-3' : 'space-y-3.5'}>
      <div className="flex items-end gap-2 flex-wrap">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Database</span>
          <select className="nv-select min-w-[180px]" value={db} onChange={(e) => setDb(e.target.value)}>
            <option value="">— select —</option>
            {databases.map((d) => <option key={d} value={d}>{d}</option>)}
          </select>
        </label>
        <button className="nv-btn-primary text-xs" onClick={check} disabled={loading || !db}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <Sparkles size={12} className="inline mr-1" />}
          Analyze
        </button>
        <AiAnalysisButton
          connectionId={connectionId}
          kind="schema-advisor"
          params={{ database: db || undefined }}
          identifier={`index-health-${db || 'all'}`}
          database={db || undefined}
          title="Análisis con IA — Index Health"
          titleAttr="Analizar la salud de índices con IA (plan de mantenimiento y DDL)"
        />
        <div className="ml-auto flex items-center gap-1 p-0.5 rounded-md bg-nv-bg border border-nv-border">
          {SUBTABS.map((s) => {
            const Icon = s.icon;
            const active = tab === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setTab(s.id)}
                className={`flex items-center gap-1.5 px-2.5 py-1 text-2xs rounded transition-colors ${active ? 'bg-nv-accent text-white shadow-sm' : 'text-nv-textSubtle hover:bg-nv-hover'}`}
              >
                <Icon size={12} className={active ? 'text-white' : 'text-nv-textMuted'} />
                {s.label}
                <span className={`ml-0.5 px-1.5 py-0.5 rounded-full text-2xs font-mono ${active ? 'bg-white/20 text-white' : s.count ? 'bg-nv-border text-nv-text' : 'bg-nv-border/60 text-nv-textMuted'}`}>{s.count}</span>
              </button>
            );
          })}
        </div>
      </div>

      {loading && !data && (
        <div className="flex items-center gap-2 text-2xs text-nv-textSubtle py-8 justify-center">
          <Loader2 size={14} className="animate-spin" /> Analyzing indexes…
        </div>
      )}

      {!db && !loading && (
        <EmptyState icon={Layers} title="Pick a database to analyze" hint="Select a database above and hit Analyze to surface unused, duplicate and redundant indexes." />
      )}

      {db && !loading && !avail && (
        <Callout tone="info">{data?.message || 'Index analysis not supported for this engine.'}</Callout>
      )}

      {avail && summary && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-2.5">
          <StatCard icon={Layers} label="Total indexes" value={summary.totalIndexes} tone="neutral" />
          <StatCard icon={CircleSlash} label="Unused" value={summary.unusedCount} tone={summary.unusedCount ? 'warn' : 'ok'} />
          <StatCard icon={Copy} label="Dup / redundant" value={summary.duplicateCount} tone={summary.duplicateCount ? 'err' : 'ok'} />
          <StatCard
            icon={DbIcon}
            label="Reclaimable"
            value={summary.unusedBytes > 0 ? bytes(summary.unusedBytes) : '—'}
            tone={summary.unusedBytes > 0 ? 'warn' : 'neutral'}
            hint={summary.unusedBytes > 0 ? 'from unused indexes' : 'PG only / none'}
          />
        </div>
      )}

      {avail && !data?.usageAvailable && tab === 'unused' && (
        <Callout tone="warn">
          <div className="flex flex-wrap items-center gap-x-3 gap-y-1">
            <span>
              Usage stats are unavailable on this server (no <code>sys</code> schema for MySQL, or stats disabled).
              Unused detection needs live usage counters — <strong>Duplicates</strong> works from the catalog alone.
            </span>
            <button
              type="button"
              className="nv-btn !py-0.5 !text-2xs"
              onClick={() => setTab('duplicates')}
              title="Cambiar al tab Duplicates"
            >
              Switch to Duplicates →
            </button>
          </div>
          <div className="mt-1.5 text-2xs text-nv-textSubtle">
            Tip: <strong>AI Analysis</strong> (arriba) usa el asesor de schema + fragmentación, así que funciona aún sin contadores de uso.
          </div>
        </Callout>
      )}
      {avail && data?.usageAvailable && tab === 'unused' && (
        <p className="text-2xs text-nv-textMuted flex items-center gap-1">
          <AlertTriangle size={11} className="text-amber-500" />
          Counters reset on server restart — “unused” means zero reads since the last reset, not forever.
        </p>
      )}

      {avail && tab === 'unused' && (
        <UnusedTable data={data} onCopy={copy} copied={copied} onCopyAll={copyAll} />
      )}
      {avail && tab === 'duplicates' && (
        <DuplicatesTable data={data} onCopy={copy} copied={copied} onCopyAll={copyAll} />
      )}
      {avail && tab === 'usage' && (
        <UsageTable data={data} />
      )}
    </div>
  );
}

function UnusedTable({
  data, onCopy, copied, onCopyAll,
}: {
  data: any; onCopy: (key: string, sql: string) => void; copied: string | null; onCopyAll: (sqls: string[]) => void;
}) {
  const rows: any[] = data?.unused ?? [];
  if (!rows.length) {
    return (
      <EmptyState
        icon={CheckCircle2}
        title="No unused indexes"
        hint="No non-unique indexes with zero reads in the current stats window. Counters reset on server restart."
        tone="ok"
      />
    );
  }
  const sqls = rows.map((r) => r.dropSql).filter(Boolean);
  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <span className="text-2xs text-nv-textSubtle">{rows.length} candidates · review before dropping</span>
        <button className="nv-btn text-2xs" onClick={() => onCopyAll(sqls)} title="Copy all DROP statements">
          <Copy size={11} className="inline mr-1" /> Copy all DROPs
        </button>
      </div>
      <div className="border border-nv-border rounded-lg overflow-hidden">
        <div className="overflow-auto max-h-[58vh]">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle uppercase tracking-wide sticky top-0">
              <tr>
                <th className="text-left px-3 py-1.5 font-medium">Table</th>
                <th className="text-left px-3 py-1.5 font-medium">Index</th>
                <th className="text-right px-3 py-1.5 font-medium">Scans</th>
                <th className="text-right px-3 py-1.5 font-medium">Rows read</th>
                <th className="text-right px-3 py-1.5 font-medium">Size</th>
                <th className="px-3 py-1.5" />
              </tr>
            </thead>
            <tbody>
              {rows.map((u, i) => {
                const key = `u${i}`;
                return (
                  <tr key={i} className="border-t border-nv-border hover:bg-nv-hover/50 even:bg-nv-bg/30">
                    <td className="px-3 py-1.5 font-mono text-nv-text">{u.schema}.<span className="text-nv-textSubtle">{u.table}</span></td>
                    <td className="px-3 py-1.5"><span className="font-mono px-1.5 py-0.5 rounded bg-nv-border/40 text-nv-text">{u.index}</span></td>
                    <td className="px-3 py-1.5 text-right text-nv-textSubtle tabular-nums">{u.scans == null ? '—' : u.scans}</td>
                    <td className="px-3 py-1.5 text-right tabular-nums">{u.rowsRead ?? 0}</td>
                    <td className="px-3 py-1.5 text-right tabular-nums text-nv-textSubtle">{bytes(u.sizeBytes)}</td>
                    <td className="px-3 py-1.5 text-right">
                      <button
                        className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-2xs transition-colors ${copied === key ? 'bg-nv-success/20 text-nv-success' : 'nv-btn'}`}
                        title={u.dropSql}
                        onClick={() => onCopy(key, u.dropSql)}
                      >
                        {copied === key ? <CopyCheck size={11} className="inline" /> : <Copy size={11} className="inline" />}
                        <span>{copied === key ? 'Copied' : 'DROP'}</span>
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function DuplicatesTable({
  data, onCopy, copied, onCopyAll,
}: {
  data: any; onCopy: (key: string, sql: string) => void; copied: string | null; onCopyAll: (sqls: string[]) => void;
}) {
  const rows: any[] = data?.duplicates ?? [];
  if (!rows.length) {
    return (
      <EmptyState
        icon={CheckCircle2}
        title="No duplicate or redundant indexes"
        hint="No indexes found that shadow another index on the same table — your index footprint is clean."
        tone="ok"
      />
    );
  }
  const sqls = rows.map((r) => r.dropSql).filter(Boolean);
  const dupCount = rows.filter((r) => r.type === 'duplicate').length;
  const redCount = rows.length - dupCount;
  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <span className="text-2xs text-nv-textSubtle flex items-center gap-2">
          <Pill tone="err">{dupCount} duplicate</Pill>
          <Pill tone="warn">{redCount} redundant</Pill>
        </span>
        <button className="nv-btn text-2xs" onClick={() => onCopyAll(sqls)} title="Copy all DROP statements">
          <Copy size={11} className="inline mr-1" /> Copy all DROPs
        </button>
      </div>
      <div className="border border-nv-border rounded-lg overflow-hidden">
        <div className="overflow-auto max-h-[58vh]">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle uppercase tracking-wide sticky top-0">
              <tr>
                <th className="text-left px-3 py-1.5 font-medium">Table</th>
                <th className="text-left px-3 py-1.5 font-medium">Index</th>
                <th className="text-left px-3 py-1.5 font-medium">Type</th>
                <th className="text-left px-3 py-1.5 font-medium">Columns</th>
                <th className="text-left px-3 py-1.5 font-medium">Covered by</th>
                <th className="px-3 py-1.5" />
              </tr>
            </thead>
            <tbody>
              {rows.map((d, i) => {
                const key = `d${i}`;
                const isDup = d.type === 'duplicate';
                return (
                  <tr key={i} className="border-t border-nv-border hover:bg-nv-hover/50 even:bg-nv-bg/30">
                    <td className="px-3 py-1.5 font-mono text-nv-text">{d.schema}.<span className="text-nv-textSubtle">{d.table}</span></td>
                    <td className="px-3 py-1.5">
                      <span className="font-mono px-1.5 py-0.5 rounded bg-nv-border/40 text-nv-text">{d.index}</span>
                      {d.unique && <span className="ml-1 text-2xs text-nv-accent">UQ</span>}
                    </td>
                    <td className="px-3 py-1.5">
                      <span className={`inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-2xs font-mono ${isDup ? 'bg-nv-danger/20 text-nv-danger' : 'bg-amber-500/20 text-amber-500'}`}>
                        {isDup ? <Copy size={10} /> : <FileWarning size={10} />}
                        {d.type}
                      </span>
                    </td>
                    <td className="px-3 py-1.5">
                      <div className="flex flex-wrap gap-1">
                        {(d.columns ?? []).map((c: string, j: number) => (
                          <span key={j} className="font-mono text-2xs px-1.5 py-0.5 rounded bg-nv-bg border border-nv-border text-nv-textSubtle">{c}</span>
                        ))}
                      </div>
                    </td>
                    <td className="px-3 py-1.5">
                      <span className="inline-flex items-center gap-1 text-nv-textSubtle">
                        <ArrowRight size={11} className="text-nv-textMuted" />
                        <span className="font-mono text-nv-text">{d.duplicateOf}</span>
                      </span>
                    </td>
                    <td className="px-3 py-1.5 text-right">
                      <button
                        className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-2xs transition-colors ${copied === key ? 'bg-nv-success/20 text-nv-success' : 'nv-btn'}`}
                        title={d.dropSql}
                        onClick={() => onCopy(key, d.dropSql)}
                      >
                        {copied === key ? <CopyCheck size={11} className="inline" /> : <Copy size={11} className="inline" />}
                        <span>{copied === key ? 'Copied' : 'DROP'}</span>
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function UsageTable({ data }: { data: any }) {
  const rows: any[] = data?.usage ?? [];
  const [q, setQ] = useState('');
  const [sortKey, setSortKey] = useState<'read' | 'scans' | 'size'>('read');

  const filtered = useMemo(() => {
    const term = q.trim().toLowerCase();
    const base = term
      ? rows.filter((r) => `${r.schema}.${r.table}.${r.index}`.toLowerCase().includes(term))
      : rows;
    const val = (r: any) =>
      sortKey === 'read' ? (r.rowsRead ?? 0) : sortKey === 'scans' ? (r.scans ?? 0) : (r.sizeBytes ?? 0);
    return [...base].sort((a, b) => val(b) - val(a));
  }, [rows, q, sortKey]);

  const maxRead = useMemo(() => Math.max(1, ...rows.map((r) => r.rowsRead ?? 0)), [rows]);

  if (!rows.length) {
    return <EmptyState icon={Activity} title="No usage stats available" hint="This engine isn't exposing per-index usage counters." />;
  }

  const SortHead = ({ k, label }: { k: typeof sortKey; label: string }) => (
    <th
      className={`text-right px-3 py-1.5 font-medium cursor-pointer select-none hover:text-nv-text ${sortKey === k ? 'text-nv-accent' : ''}`}
      onClick={() => setSortKey(k)}
    >
      {label}{sortKey === k ? ' ▾' : ''}
    </th>
  );

  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2">
        <div className="relative flex-1 max-w-xs">
          <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-nv-textMuted" />
          <input
            className="nv-input w-full pl-7 text-2xs"
            placeholder="Filter table / index…"
            value={q}
            onChange={(e) => setQ(e.target.value)}
          />
        </div>
        <span className="text-2xs text-nv-textSubtle">{filtered.length} of {rows.length}</span>
      </div>
      <div className="border border-nv-border rounded-lg overflow-hidden">
        <div className="overflow-auto max-h-[58vh]">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle uppercase tracking-wide sticky top-0">
              <tr>
                <th className="text-left px-3 py-1.5 font-medium">Table</th>
                <th className="text-left px-3 py-1.5 font-medium">Index</th>
                <SortHead k="scans" label="Scans" />
                <th className="text-left px-3 py-1.5 font-medium w-[160px]">Reads</th>
                <th className="text-right px-3 py-1.5 font-medium">Written</th>
                <SortHead k="size" label="Size" />
              </tr>
            </thead>
            <tbody>
              {filtered.map((u, i) => {
                const read = u.rowsRead ?? 0;
                const pct = Math.min(100, Math.round((read / maxRead) * 100));
                return (
                  <tr key={i} className="border-t border-nv-border hover:bg-nv-hover/50 even:bg-nv-bg/30">
                    <td className="px-3 py-1.5 font-mono text-nv-text">{u.schema}.<span className="text-nv-textSubtle">{u.table}</span></td>
                    <td className="px-3 py-1.5"><span className="font-mono px-1.5 py-0.5 rounded bg-nv-border/40 text-nv-text">{u.index}</span></td>
                    <td className="px-3 py-1.5 text-right tabular-nums">{u.scans == null ? '—' : u.scans}</td>
                    <td className="px-3 py-1.5">
                      <div className="flex items-center gap-2">
                        <div className="flex-1 h-1.5 rounded-full bg-nv-border overflow-hidden">
                          <div className="h-full bg-nv-accent/70" style={{ width: `${pct}%` }} />
                        </div>
                        <span className="tabular-nums w-16 text-right">{read}</span>
                      </div>
                    </td>
                    <td className="px-3 py-1.5 text-right tabular-nums text-nv-textSubtle">{u.rowsWritten == null ? '—' : u.rowsWritten}</td>
                    <td className="px-3 py-1.5 text-right tabular-nums text-nv-textSubtle">{bytes(u.sizeBytes)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

/* ── helpers ──────────────────────────────────────────────────────────────── */

function StatCard({
  icon: Icon, label, value, tone, hint,
}: {
  icon: any; label: string; value: React.ReactNode; tone: 'ok' | 'warn' | 'err' | 'neutral'; hint?: string;
}) {
  const tones = {
    ok: 'text-nv-success bg-nv-success/10 border-nv-success/30',
    warn: 'text-amber-500 bg-amber-500/10 border-amber-500/30',
    err: 'text-nv-danger bg-nv-danger/10 border-nv-danger/30',
    neutral: 'text-nv-accent bg-nv-accent/10 border-nv-accent/30',
  }[tone];
  return (
    <div className="border border-nv-border rounded-lg bg-nv-toolbar/30 px-3 py-2.5 flex items-center gap-3">
      <div className={`shrink-0 w-9 h-9 rounded-lg flex items-center justify-center border ${tones}`}>
        <Icon size={16} />
      </div>
      <div className="min-w-0">
        <div className="text-lg font-semibold leading-none tabular-nums">{value}</div>
        <div className="text-2xs text-nv-textSubtle mt-1 truncate">{label}{hint ? <span className="text-nv-textMuted"> · {hint}</span> : null}</div>
      </div>
    </div>
  );
}

function EmptyState({
  icon: Icon, title, hint, tone = 'neutral',
}: {
  icon: any; title: string; hint?: string; tone?: 'ok' | 'neutral';
}) {
  const color = tone === 'ok' ? 'text-nv-success' : 'text-nv-textMuted';
  return (
    <div className="border border-dashed border-nv-border rounded-lg py-10 px-4 text-center">
      <Icon size={26} className={`mx-auto mb-2 ${color}`} />
      <div className="text-xs font-medium text-nv-text">{title}</div>
      {hint && <div className="text-2xs text-nv-textSubtle mt-1 max-w-md mx-auto">{hint}</div>}
    </div>
  );
}

function Pill({ tone, children }: { tone: 'ok' | 'warn' | 'err' | 'muted'; children: React.ReactNode }) {
  const cls = {
    ok: 'bg-nv-success/20 text-nv-success',
    warn: 'bg-amber-500/20 text-amber-500',
    err: 'bg-nv-danger/20 text-nv-danger',
    muted: 'bg-nv-border text-nv-textSubtle',
  }[tone];
  return <span className={`px-1.5 py-0.5 rounded text-2xs font-mono ${cls}`}>{children}</span>;
}

function Callout({ tone, children }: { tone: 'info' | 'warn'; children: React.ReactNode }) {
  const cls = tone === 'warn' ? 'border-amber-500/40 bg-amber-500/10 text-amber-200' : 'border-nv-accent/40 bg-nv-accent/10 text-nv-text';
  const Icon = tone === 'warn' ? AlertTriangle : CheckCircle2;
  return (
    <div className={`border rounded p-2 text-2xs flex gap-2 ${cls}`}>
      <Icon size={13} className="shrink-0 mt-0.5" />
      <div>{children}</div>
    </div>
  );
}
